#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2Logic.Definitions;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Inputs;

namespace MVZ2.GameContent.HeldItems
{
    [AutoHeldItemBehaviourDefinition(VanillaHeldItemBehaviourNames.brickCannon)]
    public class BrickCannonHeldItemBehaviour : ClickContraptionTargetHeldItemBehaviour
    {
        public BrickCannonHeldItemBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void OnUseOnGrid(HeldItemTargetGrid targetGrid, IHeldItemData data, PointerInteractionData pointerParams)
        {
            var level = targetGrid.GetLevel();
            var entity = GetEntity(level, data);
            if (entity != null)
            {
                BrickCannon.Launch(entity, targetGrid.Target.GetEntityPosition());
            }
        }
    }
}
